#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char line[10005];
    fgets(line, sizeof(line), stdin); // consume endline after T
    while(T--){
        if(!fgets(line, sizeof(line), stdin)) break;
        long long incl = 0, excl = 0;
        char *p = line;
        int val, offset;
        while(sscanf(p, "%d%n", &val, &offset) == 1){
            long long new_incl = excl + val;
            long long new_excl = (incl > excl) ? incl : excl;
            incl = new_incl;
            excl = new_excl;
            p += offset;
        }
        long long ans = (incl > excl) ? incl : excl;
        printf("%lld\n", ans);
    }
    return 0;
}

