            long long new_incl = excl + val;
            long long new_excl = max(incl, excl);
            incl = new_incl;
            excl = new_excl;
        }
        cout << max(incl, excl) << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for(int t = 0; t < T; t++){
            String l = br.readLine();
            while(l != null && l.trim().isEmpty()) l = br.readLine();
            if(l == null) break;
            StringTokenizer st = new StringTokenizer(l);
            long incl = 0, excl = 0;
            while(st.hasMoreTokens()){
                long val = Long.parseLong(st.nextToken());
                long newIncl = excl + val;
                long newExcl = Math.max(incl, excl);
                incl = newIncl;
                excl = newExcl;
            }
            out.append(Math.max(incl, excl)).append('\n');
        }
        System.out.print(out.toString());
    }
}

